export async function createSwapUI({
  routerAddress,
  root = document.body,
  defaultTokenIn = "",
  defaultTokenOut = "",
}) {
  const app = await TokenSwapDApp.fromWindowEthereum({ routerAddress });

  const el = (tag, attrs = {}, children = []) => {
    const n = document.createElement(tag);
    for (const [k, v] of Object.entries(attrs)) {
      if (k === "style") Object.assign(n.style, v);
      else if (k.startsWith("on") && typeof v === "function") n.addEventListener(k.slice(2).toLowerCase(), v);
      else n.setAttribute(k, v);
    }
    for (const c of children) n.append(c);
    return n;
  };

  const status = el("div", { style: { fontFamily: "sans-serif", whiteSpace: "pre-wrap" } }, []);
  const tokenIn = el("input", { placeholder: "Token In (address)", value: defaultTokenIn, style: { width: "100%" } });
  const tokenOut = el("input", { placeholder: "Token Out (address)", value: defaultTokenOut, style: { width: "100%" } });
  const amountIn = el("input", { placeholder: "Amount In (human)", style: { width: "100%" } });
  const slippage = el("input", { placeholder: "Slippage bps (e.g. 50)", value: String(app.slippageBps), style: { width: "100%" } });

  const btnQuote = el("button", {}, ["Quote"]);
  const btnApprove = el("button", {}, ["Approve Max"]);
  const btnSwap = el("button", {}, ["Swap"]);

  const wrap = el(
    "div",
    { style: { maxWidth: "520px", margin: "16px auto", display: "grid", gap: "8px" } },
    [
      el("div", { style: { fontFamily: "sans-serif", fontSize: "18px", fontWeight: "600" } }, ["Token Swap"]),
      el("div", { style: { fontFamily: "sans-serif", fontSize: "12px", opacity: "0.8" } }, [
        `Router: ${routerAddress}`,
      ]),
      tokenIn,
      tokenOut,
      amountIn,
      slippage,
      el("div", { style: { display: "flex", gap: "8px" } }, [btnQuote, btnApprove, btnSwap]),
      status,
    ]
  );

  root.append(wrap);

  const setStatus = (msg) => (status.textContent = String(msg));

  const readInputs = async () => {
    const tIn = tokenIn.value.trim();
    const tOut = tokenOut.value.trim();
    assert(isAddress(tIn), "Invalid token in");
    assert(isAddress(tOut), "Invalid token out");
    const amtHuman = amountIn.value.trim();
    assert(amtHuman && !Number.isNaN(Number(amtHuman)), "Invalid amount");
    const amt = await app.parseTokenAmount(tIn, amtHuman);
    const slip = Number(slippage.value.trim());
    assert(Number.isFinite(slip) && slip >= 0 && slip <= 10_000, "Invalid slippage bps");
    return { tIn, tOut, amt, slip };
  };

  btnQuote.addEventListener("click", async () => {
    try {
      setStatus("Quoting...");
      const { tIn, tOut, amt, slip } = await readInputs();
      const quote = await app.getQuoteExactIn({ amountIn: amt, path: [tIn, tOut] });
      const minOut = minOutFromQuote(quote.amountOut, slip);
      const outFmt = await app.formatTokenAmount(tOut, quote.amountOut);
      const minFmt = await app.formatTokenAmount(tOut, minOut);
      setStatus(`Quote out: ${outFmt}\nMin out (@${slip} bps): ${minFmt}`);
    } catch (e) {
      setStatus(`Error: ${e?.message || e}`);
    }
  });

  btnApprove.addEventListener("click", async () => {
    try {
      setStatus("Approving max...");
      await app.connect();
      const { tIn, amt } = await readInputs();
      const res = await app.ensureApproval({
        tokenAddress: tIn,
        spender: app.routerAddress,
        amountRequired: amt,
        approveMax: true,
      });
      setStatus(`Approval: ${res.status}\nAllowance: ${res.allowance.toString()}\nTx: ${res.tx?.hash || "n/a"}`);
    } catch (e) {
      setStatus(`Error: ${e?.message || e}`);
    }
  });

  btnSwap.addEventListener("click", async () => {
    try {
      setStatus("Swapping...");
      await app.connect();
      const { tIn, tOut, amt, slip } = await readInputs();
      const res = await app.swapExactTokensForTokens({
        tokenIn: tIn,
        tokenOut: tOut,
        amountIn: amt,
        slippageBps: slip,
        approveMax: true,
      });
      setStatus(
        `Swap sent: ${res.tx.hash}\nMin out: ${await app.formatTokenAmount(tOut, res.amountOutMin)}\nConfirmed in block: ${res.receipt.blockNumber}`
      );
    } catch (e) {
      setStatus(`Error: ${e?.message || e}`);
    }
  });

  return app;
}